<?php
namespace App\Models\Customers; use App\Models\User; use Illuminate\Database\Eloquent\Attributes\Fillable; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo;
#[Fillable(['company_id','customer_id','loyalty_account_id','transaction_type','points','reference_type','reference_id','description','expires_at','created_by','metadata'])] class CustomerLoyaltyTransaction extends Model {protected function casts():array{return ['expires_at'=>'datetime','metadata'=>'array'];} public function customer():BelongsTo{return $this->belongsTo(Customer::class);} public function account():BelongsTo{return $this->belongsTo(CustomerLoyaltyAccount::class,'loyalty_account_id');} public function creator():BelongsTo{return $this->belongsTo(User::class,'created_by');}}
